class Rectangle:
    def __init__(self, length, width):
        self._length = length
        self._width = width

    @property
    def length(self):
        return abs(self._length)

    @length.setter
    def length(self, value):
        self._length = abs(value)

    @property
    def width(self):
        return abs(self._width)

    @width.setter
    def width(self, value):
        self._width = abs(value)

    @property
    def area(self):
        return self.length * self.width

if __name__ == "__main__":
    length, width = map(float, input().split())
    rect = Rectangle(length, width)
    print(f"Length: {rect.length}")
    print(f"Width: {rect.width}")
    print(f"Area: {rect.area}")
